     1→import React, { useState, useEffect, useCallback } from 'react';
     2→import { Modal } from '../../components/Modal';
     3→import { RecurrencePicker } from '../../components/RecurrencePicker';
     4→import { CustomFieldEditor } from '../../components/CustomFieldEditor';
     5→import { DependencyPicker } from '../../components/DependencyPicker';
     6→import { DependentShiftConfirmation } from '../../components/DependentShiftConfirmation';
     7→import AssigneePicker from '../../components/AssigneePicker';
     8→import FileUpload from '../../components/FileUpload';
     9→import AttachmentList from '../../components/AttachmentList';
    10→import ImagePreviewModal from '../../components/ImagePreviewModal';
    11→import { useKanbanStore } from '../../stores/useKanbanStore';
    12→import { useTimeTrackingStore } from '../../stores/useTimeTrackingStore';
    13→import { useSettingsStore } from '../../stores/useSettingsStore';
    14→import { useTemplateStore } from '../../stores/useTemplateStore';
    15→import { calculateDependentShifts, shouldAutoShift } from '../../services/taskDependencyShift';
    16→import type { Task, TaskPriority, TaskStatus, EffortEstimate, CustomStatus, DependencyType, TaskDependency, TaskAttachment } from '../../types';
    17→import type { FieldDefinition } from '../../types/customFields';
    18→
    19→/**
    20→ * TaskCustomFields - Separate component to properly use hooks
    21→ * Extracted to avoid Rules of Hooks violation (hooks cannot be called inside IIFEs)
    22→ */
    23→const TaskCustomFields: React.FC<{
    24→  task: Task;
    25→  onSave: (taskId: string, updates: Partial<Task>) => void;
    26→}> = ({ task, onSave }) => {
    27→  const { customFieldDefinitions } = useSettingsStore();
    28→  const taskFields = customFieldDefinitions.tasks;
    29→
    30→  if (taskFields.length === 0) return null;
    31→
    32→  return (
    33→    <div>
    34→      <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
    35→        Custom Fields
    36→      </label>
    37→      <div className="space-y-3">
    38→        {taskFields.map((field: FieldDefinition) => {
    39→          const currentValue = task?.customFields?.[field.id];
    40→
    41→          return (
    42→            <div key={field.id}>
    43→              <label className="block text-xs font-medium text-text-light-primary dark:text-text-dark-primary mb-1">
    44→                {field.name}
    45→                {field.required && (
    46→                  <span className="text-status-error-text dark:text-status-error-text-dark ml-1">*</span>
    47→                )}
    48→              </label>
    49→              {field.description && (
    50→                <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary mb-1">
    51→                  {field.description}
    52→                </p>
    53→              )}
    54→              <CustomFieldEditor
    55→                field={field}
    56→                value={currentValue}
    57→                onChange={(value) => {
    58→                  if (!task) return;
    59→                  const updatedCustomFields = {
    60→                    ...task.customFields,
    61→                    [field.id]: value,
    62→                  };
    63→                  onSave(task.id, { customFields: updatedCustomFields });
    64→                }}
    65→              />
    66→            </div>
    67→          );
    68→        })}
    69→      </div>
    70→    </div>
    71→  );
    72→};
    73→
    74→interface CardDetailPanelProps {
    75→  task: Task | null;
    76→  isOpen: boolean;
    77→  onClose: () => void;
    78→  onSave: (taskId: string, updates: Partial<Task>) => void;
    79→  columns: Array<{ id: string; title: string; color: string }>;
    80→  initialTab?: 'subtasks' | 'checklist' | 'comments' | 'activity' | 'timetracking' | 'attachments';
    81→  onCardClick?: (task: Task) => void;
    82→}
    83→
    84→/**
    85→ * Card Detail Panel
    86→ * Full-screen modal for viewing and editing task details
    87→ *
    88→ * Features:
    89→ * - Left side: Task metadata (title, description, dates, priority, tags, status)
    90→ * - Right side: Tabs (Checklist, Comments, Activity Log)
    91→ * - Inline editing (auto-save on blur)
    92→ * - Keyboard shortcuts (Esc to close, Cmd+Enter to save)
    93→ * - Tab persistence (remembers last active tab)
    94→ * - Responsive design (mobile, tablet, desktop)
    95→ */
    96→export const CardDetailPanel: React.FC<CardDetailPanelProps> = ({
    97→  task,
    98→  isOpen,
    99→  onClose,
   100→  onSave,
   101→  columns,
   102→  initialTab,
   103→  onCardClick,
   104→}) => {
