   109→    updateChecklistItem,
   110→    deleteChecklistItem,
   111→    toggleChecklistItem,
   112→    addComment,
   113→    addSubtask,
   114→    deleteSubtask,
   115→    toggleSubtask,
   116→    addDependency,
   117→    removeDependency,
   118→    getBlocked,
   119→    updateEffort,
   120→    updateCustomStatus,
   121→    startTimer,
   122→    stopTimer: stopKanbanTimer,
   123→    updateTimeEstimate,
   124→    setTaskRecurrence,
   125→    applyDependentShifts,
   126→    addAttachment,
   127→    deleteAttachment,
   128→  } = useKanbanStore();
   129→
   130→  // Time tracking store (Phase A: Time Tracking Integration)
   131→  const {
   132→    getEntriesForCard,
   133→    getTotalTimeForCard,
   134→    startTimerForCard,
   135→    stopTimer,
   136→    activeEntry,
   137→  } = useTimeTrackingStore();
   138→
   139→  // Template store (P2: Task Templates)
   140→  const { createTemplate } = useTemplateStore();
   141→
   142→  // Tab state with persistence
   143→  const [activeTab, setActiveTab] = useState<'subtasks' | 'checklist' | 'comments' | 'activity' | 'timetracking' | 'attachments'>(() => {
   144→    if (initialTab) return initialTab;
   145→    const saved = localStorage.getItem('kanban-detail-panel-tab');
   146→    return (saved as 'subtasks' | 'checklist' | 'comments' | 'activity' | 'timetracking' | 'attachments') || 'subtasks';
   147→  });
   148→
   149→  // Sync activeTab with initialTab when it changes
   150→  useEffect(() => {
   151→    if (initialTab) {
   152→      setActiveTab(initialTab);
   153→    }
   154→  }, [initialTab]);
   155→
   156→  // Local state for editing (synced with task prop)
   157→  const [title, setTitle] = useState('');
   158→  const [description, setDescription] = useState('');
   159→  const [startDate, setStartDate] = useState<string | null>(null);
   160→  const [dueDate, setDueDate] = useState<string | null>(null);
   161→  const [priority, setPriority] = useState<TaskPriority>('medium');
   162→  const [tags, setTags] = useState<string[]>([]);
   163→  const [status, setStatus] = useState<TaskStatus>('todo');
   164→  const [newTag, setNewTag] = useState('');
   165→  const [effort, setEffort] = useState<EffortEstimate | undefined>(undefined);
   166→  const [customStatus, setCustomStatus] = useState<CustomStatus | undefined>(undefined);
   167→  const [timeEstimate, setTimeEstimate] = useState<number | undefined>(undefined);
   168→  const [assignees, setAssignees] = useState<string[]>([]);
   169→  const [progress, setProgress] = useState<number>(0); // Phase 1.5: Progress %
   170→
   171→  // P1: Recurring tasks state
   172→  const [showRecurrencePicker, setShowRecurrencePicker] = useState(false);
   173→
   174→  // Phase 1.2: Auto-shift dependent tasks
   175→  const { autoShiftDependentTasks, setAutoShiftDependentTasks } = useSettingsStore();
   176→  const [pendingShifts, setPendingShifts] = useState<Array<{taskId: string; newStartDate: string | null; newDueDate: string | null; reason: string}> | null>(null);
   177→
   178→  // Checklist state
   179→  const [newChecklistItem, setNewChecklistItem] = useState('');
   180→
   181→  // Comment state
