   189→  const [newSubtaskDueDate, setNewSubtaskDueDate] = useState('');
   190→
   191→  // Phase 3.2: Attachment state
   192→  const [previewAttachment, setPreviewAttachment] = useState<TaskAttachment | null>(null);
   193→
   194→  // No longer need local state for dependency selection - handled by DependencyPicker
   195→
